import React from 'react';
import Hero from '../Hero';
import Spacing from '../Spacing';
import About from '../About';

export default function AnaSayfa() {
  const heroTitles = [
    'Konferans Platformu',
    'İnovasyon Merkezi',
    'Ağ Oluşturma',
  ];

  const features = [
    'Profesyonel Ağ Oluşturma Fırsatları',
    'Endüstri Liderlerinden Sunum ve Workshops',
    'Kişisel Gelişim ve Mentoring',
    'Eksklusif Networking Etkinlikleri',
  ];

  const services = [
    {
      title: 'Konferans Kayıtı',
      description: 'Konferansa kolayca kaydolun ve özel avantajları açın.',
      icon: 'mdi:clipboard-check',
    },
    {
      title: 'Networking Fırsatları',
      description: 'Endüstri profesyonelleri ile bağlantı kurun.',
      icon: 'mdi:account-multiple',
    },
    {
      title: 'Özel İçerik',
      description: 'Katılımcılara yönelik özel sunum ve materyallere erişim.',
      icon: 'mdi:file-document',
    },
    {
      title: '24/7 Destek',
      description: 'Tüm sorularınız için her zaman yardım sunuyoruz.',
      icon: 'mdi:headset',
    },
  ];

  const testimonials = [
    {
      text: 'Bu konferans benim kariyer yolumu tamamen değiştirdi. Harika bir deneyimdi!',
      name: 'Ahmet Yılmaz',
      position: 'Şirket Müdürü',
      image: 'https://via.placeholder.com/100x100?text=Ahmet',
    },
    {
      text: 'Networking fırsatları ve sunumlar çok değerli bilgiler sağladı.',
      name: 'Fatma Demir',
      position: 'Proje Yöneticisi',
      image: 'https://via.placeholder.com/100x100?text=Fatma',
    },
    {
      text: 'Profesyonel bir etkinlik. Tüm katılımcılara tavsiye ederim.',
      name: 'Mehmet Şahin',
      position: 'İş Analisti',
      image: 'https://via.placeholder.com/100x100?text=Mehmet',
    },
  ];

  const facts = [
    { number: '500+', title: 'Katılımcı' },
    { number: '50+', title: 'Konuşmacı' },
    { number: '100+', title: 'Şirket' },
    { number: '8', title: 'Saat Konferans' },
  ];

  return (
    <>
      {/* Main banner */}
      <section id="main-banner" className="mb-5">
        <img
          src="/images/konf_banner.jpeg"
          alt="Konf Banner"
          className="img-fluid w-100"
        />
      </section>

      {/* About Section */}
      <About
        thumbnail="https://via.placeholder.com/500x600?text=Konferans"
        uperTitle="Hakkımızda"
        title="Önde Gelen Konferans"
        subTitle="2026 Konferansı, endüstrideki en iyi profesyonelleri bir araya getiren ve yenilikçi fikirler paylaşılan bir platformdur. Katılımcılar ağ oluşturma, öğrenme ve kariyer gelişimi fırsatları bulacaklar."
        featureList={features}
        btnText="Daha Fazla Bilgi"
        btnUrl="#iletisim"
      />

      <Spacing lg="80" md="60" />

      {/* Fun Facts Section */}
      <section className="py-5 bg-light">
        <div className="container">
          <div className="row text-center">
            {facts.map((fact, index) => (
              <div className="col-md-3 col-sm-6 mb-4" key={index}>
                <h3 className="cs_primary_color" style={{ fontSize: '2.5rem', fontWeight: 'bold' }}>
                  {fact.number}
                </h3>
                <p className="text-muted">{fact.title}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      <Spacing lg="80" md="60" />

      {/* CTA Section */}
      <section className="py-5 bg-primary text-white">
        <div className="container text-center">
          <h2 className="mb-3">Konferansa Katılmaya Hazır mısınız?</h2>
          <p className="mb-4 fs-5">
            Bugün kayıt olun ve ağ oluşturma, öğrenme ve kariyer gelişimi fırsatlarından yararlanın.
          </p>
          <a href="/kayit-ol" className="btn btn-light btn-lg">
            Şimdi Kayıt Ol
          </a>
        </div>
      </section>

      <Spacing lg="50" md="40" />
    </>
  );
}
